import{_ as t,o as a,c as r,ag as n}from"./chunks/framework.DFmy_ALI.js";const u=JSON.parse('{"title":"Secure Flows","description":"","frontmatter":{},"headers":[],"relativePath":"guide/secure-flows.md","filePath":"guide/secure-flows.md"}'),i={name:"guide/secure-flows.md"};function s(o,e,c,l,d,h){return a(),r("div",null,[...e[0]||(e[0]=[n(`<h1 id="secure-flows" tabindex="-1">Secure Flows <a class="header-anchor" href="#secure-flows" aria-label="Permalink to &quot;Secure Flows&quot;">​</a></h1><p>Astro SDKs are designed to prevent merchants from accidentally handling bank secrets, customer OTPs, or Open Banking credentials directly.</p><h2 id="ownership-boundaries" tabindex="-1">Ownership boundaries <a class="header-anchor" href="#ownership-boundaries" aria-label="Permalink to &quot;Ownership boundaries&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Responsibility</th><th>Correct owner</th></tr></thead><tbody><tr><td>Merchant API key</td><td>Merchant backend only</td></tr><tr><td>Payment session creation</td><td>Merchant backend</td></tr><tr><td>Customer alias or IBAN entry</td><td>Astro hosted checkout or SDK-controlled surface</td></tr><tr><td>OTP or push approval</td><td>Bank through Astro-hosted authorization</td></tr><tr><td>Open Banking consent decision</td><td>Astro hosted consent screen</td></tr><tr><td>Token exchange</td><td>Merchant or TPP backend</td></tr><tr><td>Final fulfilment</td><td>Merchant backend after signed webhook</td></tr></tbody></table><h2 id="payment-security" tabindex="-1">Payment security <a class="header-anchor" href="#payment-security" aria-label="Permalink to &quot;Payment security&quot;">​</a></h2><p>The merchant backend creates a session and receives a hosted checkout URL. The customer authorizes in Astro. If OTP is selected, the OTP is submitted to Astro and verified through the bank callback interface. If push is selected, the bank controls approval and Astro tracks the state.</p><p>The merchant site must not render its own OTP box for bank authentication. That would train customers to enter bank authorization codes into arbitrary merchant pages.</p><h2 id="subscription-security" tabindex="-1">Subscription security <a class="header-anchor" href="#subscription-security" aria-label="Permalink to &quot;Subscription security&quot;">​</a></h2><p>Recurring mandates require clear customer approval before any future charge can happen. The approval page must show:</p><ul><li>Merchant name</li><li>Amount or maximum amount</li><li>Currency</li><li>Billing frequency</li><li>Start date and expiry</li><li>Cancellation rights</li><li>Bank account or alias being used, masked where required</li></ul><p>Charges after approval do not require the customer to re-enter OTP every month unless the mandate rules, bank policy, or risk engine require step-up authorization.</p><h2 id="presented-payment-security" tabindex="-1">Presented-payment security <a class="header-anchor" href="#presented-payment-security" aria-label="Permalink to &quot;Presented-payment security&quot;">​</a></h2><p>Presented QR and NFC flows must obey the same boundary:</p><ul><li>merchant UI may show a QR code or expose an NFC target</li><li>merchant UI must not collect OTP or bank secrets</li><li>Astro or the bank-controlled surface must own the final SCA step</li></ul><h3 id="presented-payment-trust-chain" tabindex="-1">Presented-payment trust chain <a class="header-anchor" href="#presented-payment-trust-chain" aria-label="Permalink to &quot;Presented-payment trust chain&quot;">​</a></h3><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  A[Merchant backend] --&gt; B[Presentment created]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  B --&gt; C[Customer scans or taps]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  C --&gt; D[Astro hosted or secure SDK surface]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  D --&gt; E[Bank OTP / push / SCA]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  E --&gt; F[Signed final event]</span></span></code></pre></div><h3 id="bad-presented-payment-patterns-to-reject" tabindex="-1">Bad presented-payment patterns to reject <a class="header-anchor" href="#bad-presented-payment-patterns-to-reject" aria-label="Permalink to &quot;Bad presented-payment patterns to reject&quot;">​</a></h3><ul><li>Static QR with no expiry or claim lifecycle</li><li>Merchant page asks the customer to type the bank OTP directly</li><li>Subscription approval begins from QR but skips a visible mandate summary</li><li>QR or NFC claim is treated as a completed payment without bank verification</li></ul><h2 id="open-banking-security" tabindex="-1">Open Banking security <a class="header-anchor" href="#open-banking-security" aria-label="Permalink to &quot;Open Banking security&quot;">​</a></h2><p>Open Banking consent is OAuth-style. The hosted consent page must show the TPP or merchant name, the bank, selected accounts, requested scopes, duration, and purpose before approval.</p><p>Tokens are scoped. A token granted for <code>balances:read</code> must not read transactions. A token granted for one bank account must not access another account.</p><h2 id="webhook-security" tabindex="-1">Webhook security <a class="header-anchor" href="#webhook-security" aria-label="Permalink to &quot;Webhook security&quot;">​</a></h2><p>Treat webhooks as the final source for fulfilment, but verify them before trusting them:</p><h3 id="bad-credit-finance-patterns-to-reject" tabindex="-1">Bad Credit &amp; Finance patterns to reject <a class="header-anchor" href="#bad-credit-finance-patterns-to-reject" aria-label="Permalink to &quot;Bad Credit &amp; Finance patterns to reject&quot;">​</a></h3><ul><li>Merchant receives raw customer transaction history when only a financed-checkout status is needed.</li><li>Generic Open Banking consent is reused for finance eligibility without telling the customer.</li><li>Murabaha terms hide cash price, profit amount, total sale price, or repayment schedule until after acceptance.</li><li>Merchant fulfils on <code>finance_offer.accepted</code> before final financier-to-merchant payment confirmation.</li></ul><ol><li>Use the raw request body.</li><li>Verify <code>X-OpenWave-Signature</code>.</li><li>Check timestamp freshness.</li><li>Deduplicate by event ID.</li><li>Persist before returning <code>2xx</code>.</li></ol><h2 id="bad-integration-patterns-to-reject" tabindex="-1">Bad integration patterns to reject <a class="header-anchor" href="#bad-integration-patterns-to-reject" aria-label="Permalink to &quot;Bad integration patterns to reject&quot;">​</a></h2><ul><li>Merchant frontend holds <code>mk_...</code> keys.</li><li>Merchant page collects bank OTP directly.</li><li>Open Banking scopes are hidden in a settings page instead of shown before consent.</li><li>Orders are fulfilled from browser callback parameters without webhook verification.</li><li>Production webhooks accept unsigned payloads.</li></ul>`,28)])])}const m=t(i,[["render",s]]);export{u as __pageData,m as default};
